/**
 * test-agent.js
 * mechsense-agent.js の動作確認テスト
 * GATEWAY_SPEC.md の会話例 3 ケースを実行
 *
 * 前提: mechsense-api サーバーが localhost:3000 で起動済みであること
 * 起動: node server.js
 */

'use strict';

const { query } = require('./mechsense-agent');

const TESTS = [
  {
    label: 'Case 1: ばね安全確認',
    input: '線径2mm、コイル径15mm、有効巻数5巻のSW-Bばねに50N かけても大丈夫ですか？',
  },
  {
    label: 'Case 2: ボルト締付トルク照会',
    input: 'M10の10.9ボルト、アルミ板への締め付けトルクを教えてください。潤滑あります。',
  },
  {
    label: 'Case 3: 共振危険判定',
    input: '3000rpm で動作するモータに、このばね（d=2, D=15, Na=5, SW-B）を使えますか？',
  },
];

async function run() {
  let passed = 0;
  let failed = 0;

  for (const test of TESTS) {
    console.log(`\n${'─'.repeat(60)}`);
    console.log(`${test.label}`);
    console.log(`質問: ${test.input}`);
    console.log('─'.repeat(60));

    try {
      const answer = await query(test.input);
      console.log(answer);

      // 最低限の検証: 回答が空でないこと
      if (answer && answer.trim().length > 0) {
        console.log('\n✓ PASS');
        passed++;
      } else {
        console.log('\n✗ FAIL: 空の回答');
        failed++;
      }
    } catch (err) {
      console.error(`\n✗ FAIL: ${err.message}`);
      failed++;
    }
  }

  console.log(`\n${'═'.repeat(60)}`);
  console.log(`テスト結果: ${passed} PASS / ${failed} FAIL / ${TESTS.length} 合計`);
  process.exit(failed > 0 ? 1 : 0);
}

run();

